@HandlerChain(file = "handler-chain.xml")
class SecurityHandler implements SOAPHandler<SOAPMessageContext> {
    
    private static final long TIMESTAMP_FRESHNESS_LIMIT = 5 * 60 * 1000;
    private static final Set<String> processedTimestamps = Collections.synchronizedSet(new HashSet<>());
    
    @Override
    public Set<QName> getHeaders() {
        QName securityHeader = new QName(
            "http://docs.oasis-open.org/wss/2004/01/oasis-200401-wss-wssecurity-secext-1.0.xsd", 
            "Security"
        );
        Set<QName> headers = new HashSet<>();
        headers.add(securityHeader);
        return headers;
    }
    
    @Override
    public boolean handleMessage(SOAPMessageContext context) {
        Boolean outbound = (Boolean) context.get(MessageContext.MESSAGE_OUTBOUND_PROPERTY);
        
        if (!outbound) {
            try {
                SOAPMessage message = context.getMessage();
                SOAPEnvelope envelope = message.getSOAPPart().getEnvelope();
                SOAPHeader header = envelope.getHeader();
                
                if (header == null) {
                    throw new SOAPFaultException(createFault("Missing SOAP Header"));
                }
                
                TimestampInfo timestampInfo = extractTimestamp(header);
                
                if (timestampInfo == null) {
                    throw new SOAPFaultException(createFault("Missing WS-Security Timestamp"));
                }
                
                validateTimestamp(timestampInfo);
                
                context.put("timestamp.created", timestampInfo.created);
                context.put("timestamp.expires", timestampInfo.expires);
                
            } catch (SOAPException e) {
                throw new SOAPFaultException(createFault("SOAP processing error: " + e.getMessage()));
            }
        }
        
        return true;
    }
    
    private TimestampInfo extractTimestamp(SOAPHeader header) throws SOAPException {
        Iterator<?> securityHeaders = header.getChildElements(
            new QName("http://docs.oasis-open.org/wss/2004/01/oasis-200401-wss-wssecurity-secext-1.0.xsd", "Security")
        );
        
        while (securityHeaders.hasNext()) {
            SOAPElement securityElement = (SOAPElement) securityHeaders.next();
            
            Iterator<?> timestamps = securityElement.getChildElements(
                new QName("http://docs.oasis-open.org/wss/2004/01/oasis-200401-wss-wssecurity-utility-1.0.xsd", "Timestamp")
            );
            
            while (timestamps.hasNext()) {
                SOAPElement timestampElement = (SOAPElement) timestamps.next();
                
                String timestampId = timestampElement.getAttributeValue(
                    new QName("http://docs.oasis-open.org/wss/2004/01/oasis-200401-wss-wssecurity-utility-1.0.xsd", "Id")
                );
                
                Iterator<?> created = timestampElement.getChildElements(
                    new QName("http://docs.oasis-open.org/wss/2004/01/oasis-200401-wss-wssecurity-utility-1.0.xsd", "Created")
                );
                
                Iterator<?> expires = timestampElement.getChildElements(
                    new QName("http://docs.oasis-open.org/wss/2004/01/oasis-200401-wss-wssecurity-utility-1.0.xsd", "Expires")
                );
                
                String createdValue = null;
                String expiresValue = null;
                
                if (created.hasNext()) {
                    SOAPElement createdElement = (SOAPElement) created.next();
                    createdValue = createdElement.getValue();
                }
                
                if (expires.hasNext()) {
                    SOAPElement expiresElement = (SOAPElement) expires.next();
                    expiresValue = expiresElement.getValue();
                }
                
                if (createdValue != null) {
                    return new TimestampInfo(timestampId, createdValue, expiresValue);
                }
            }
        }
        
        return null;
    }
    
    private void validateTimestamp(TimestampInfo timestampInfo) {
        try {
            SimpleDateFormat sdf = new SimpleDateFormat("yyyy-MM-dd'T'HH:mm:ss.SSS'Z'");
            sdf.setTimeZone(TimeZone.getTimeZone("UTC"));
            
            Date createdDate = sdf.parse(timestampInfo.created);
            Date now = new Date();
            
            if (createdDate.after(now)) {
                throw new SOAPFaultException(createFault("Timestamp is in the future"));
            }
            
            long age = now.getTime() - createdDate.getTime();
            if (age > TIMESTAMP_FRESHNESS_LIMIT) {
                throw new SOAPFaultException(createFault("Timestamp is too old"));
            }
            
            if (timestampInfo.expires != null) {
                Date expiresDate = sdf.parse(timestampInfo.expires);
                if (now.after(expiresDate)) {
                    throw new SOAPFaultException(createFault("Timestamp has expired"));
                }
            }
            
            String uniqueKey = timestampInfo.id != null ? timestampInfo.id : timestampInfo.created;
            
            synchronized (processedTimestamps) {
                if (processedTimestamps.contains(uniqueKey)) {
                    throw new SOAPFaultException(createFault("Replay attack detected - timestamp already processed"));
                }
                processedTimestamps.add(uniqueKey);
            }
            
            cleanupOldTimestamps();
            
        } catch (java.text.ParseException e) {
            throw new SOAPFaultException(createFault("Invalid timestamp format"));
        }
    }
    
    private void cleanupOldTimestamps() {
        if (processedTimestamps.size() > 10000) {
            synchronized (processedTimestamps) {
                processedTimestamps.clear();
            }
        }
    }
    
    private SOAPFault createFault(String message) {
        try {
            SOAPFactory factory = SOAPFactory.newInstance();
            SOAPFault fault = factory.createFault();
            fault.setFaultString(message);
            fault.setFaultCode(new QName("http://schemas.xmlsoap.org/soap/envelope/", "Client"));
            return fault;
        } catch (SOAPException e) {
            throw new RuntimeException(e);
        }
    }
    
    @Override
    public boolean handleFault(SOAPMessageContext context) {
        return true;
    }
    
    @Override
    public void close(MessageContext context) {
    }
    
    private static class TimestampInfo {
        String id;
        String created;
        String expires;
        
        TimestampInfo(String id, String created, String expires) {
            this.id = id;
            this.created = created;
            this.expires = expires;
        }
    }
}

