class ClientSecurityHandler implements SOAPHandler<SOAPMessageContext> {
    
    @Override
    public Set<QName> getHeaders() {
        return null;
    }
    
    @Override
    public boolean handleMessage(SOAPMessageContext context) {
        Boolean outbound = (Boolean) context.get(MessageContext.MESSAGE_OUTBOUND_PROPERTY);
        
        if (outbound) {
            try {
                SOAPMessage message = context.getMessage();
                SOAPEnvelope envelope = message.getSOAPPart().getEnvelope();
                SOAPHeader header = envelope.getHeader();
                
                if (header == null) {
                    header = envelope.addHeader();
                }
                
                addTimestamp(header);
                
                message.saveChanges();
                
            } catch (SOAPException e) {
                throw new RuntimeException("Error adding security header", e);
            }
        }
        
        return true;
    }
    
    private void addTimestamp(SOAPHeader header) throws SOAPException {
        SOAPElement security = header.addChildElement(
            "Security",
            "wsse",
            "http://docs.oasis-open.org/wss/2004/01/oasis-200401-wss-wssecurity-secext-1.0.xsd"
        );
        
        security.addNamespaceDeclaration(
            "wsu",
            "http://docs.oasis-open.org/wss/2004/01/oasis-200401-wss-wssecurity-utility-1.0.xsd"
        );
        
        SOAPElement timestamp = security.addChildElement("Timestamp", "wsu");
        
        String timestampId = "TS-" + UUID.randomUUID().toString();
        timestamp.addAttribute(new QName("http://docs.oasis-open.org/wss/2004/01/oasis-200401-wss-wssecurity-utility-1.0.xsd", "Id", "wsu"), timestampId);
        
        SimpleDateFormat sdf = new SimpleDateFormat("yyyy-MM-dd'T'HH:mm:ss.SSS'Z'");
        sdf.setTimeZone(TimeZone.getTimeZone("UTC"));
        
        Date now = new Date();
        Date expires = new Date(now.getTime() + 5 * 60 * 1000);
        
        SOAPElement created = timestamp.addChildElement("Created", "wsu");
        created.addTextNode(sdf.format(now));
        
        SOAPElement expiresElement = timestamp.addChildElement("Expires", "wsu");
        expiresElement.addTextNode(sdf.format(expires));
    }
    
    @Override
    public boolean handleFault(SOAPMessageContext context) {
        return true;
    }
    
    @Override
    public void close(MessageContext context) {
    }
}